#include<bits/stdc++.h>
using namespace std;
int a[500005], pre[500005], dp[500005];
map<int, int>m;
int main()
{
	int n, k;
	cin >> n >> k;
	for(int i = 1; i <= n; i++){
		cin >> a[i];
		pre[i] = pre[i - 1] ^ a[i];

	}
	int cnt = 0;
    m[0] = 0;
	for(int i = 1; i <= n; i++){
        dp[i] = dp[i - 1];
        int sum = k ^ pre[i];
        if(m.count(pre[i] ^ k))dp[i] = max(dp[i], dp[m[sum]] + 1);
        m[pre[i]] = i;
	}
	cout << dp[n];
}
